158→func extractAcademics(data map[string]any) *model.InstitutionAcademics {
159→	nces := jsonbObject(data, "nces")
160→	if nces == nil {
161→		return nil
162→	}
163→
164→	a := &model.InstitutionAcademics{
165→		InstitutionType:    jsonbString(nces, "ownership"),
166→		HighestDegree:      jsonbString(nces, "degrees_awarded_highest"),
167→		Enrollment:         jsonbInt(nces, "size"),
168→		GradEnrollment:     jsonbInt(nces, "grad_students"),
169→		StudentFacultyRatio: jsonbInt(nces, "demographics_student_faculty_ratio"),
170→		FullTimeFacultyRate: jsonbFloat(nces, "ft_faculty_rate"),
171→		Gender:             deriveGender(nces),
172→		OnlineOnly:         jsonbBool01(nces, "online_only"),
173→	}
174→	return a
175→}
