177→// deriveGender returns "men-only", "women-only", or "coed" based on the
178→// nces.men_only and nces.women_only JSONB values.
179→func deriveGender(nces map[string]any) *string {
180→	menOnly := jsonbBool01(nces, "men_only")
181→	womenOnly := jsonbBool01(nces, "women_only")
182→	if menOnly != nil && *menOnly {
183→		s := "men-only"
184→		return &s
185→	}
186→	if womenOnly != nil && *womenOnly {
187→		s := "women-only"
188→		return &s
189→	}
190→	// If both are present and false, or if either is missing, default to coed.
191→	if menOnly != nil || womenOnly != nil {
192→		s := "coed"
193→		return &s
194→	}
195→	return nil
196→}
