232→func extractRankings(data map[string]any) *model.InstitutionRankings {
233→	r := &model.InstitutionRankings{}
234→
235→	if obj := jsonbObject(data, "us_news____national_universities"); obj != nil {
236→		r.UsNewsNational = rankValue(obj)
237→	}
238→	if obj := jsonbObject(data, "us_news____liberal_arts_colleges"); obj != nil {
239→		r.UsNewsLiberalArts = rankValue(obj)
240→	}
241→	if obj := jsonbObject(data, "forbes_____"); obj != nil {
