265→// rankValue extracts the rank integer from a ranking object, only if method == "rank".
266→func rankValue(obj map[string]any) *int {
267→	method := jsonbString(obj, "method")
268→	if method == nil || *method != "rank" {
269→		return nil
270→	}
271→	return jsonbInt(obj, "rank")
272→}
